import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../api';
import './Profile.css';

export default function Profile() {
  const { user, updateUser, logout } = useAuth();
  const navigate = useNavigate();
  const [isEditing, setIsEditing] = useState(false);
  const [form, setForm] = useState({ name: '', rollNumber: '', course: '', department: '' });
  const [saving, setSaving] = useState(false);
  const [message, setMessage] = useState('');

  useEffect(() => {
    if (user) {
      setForm({
        name: user.name || '',
        rollNumber: user.rollNumber || '',
        course: user.course || '',
        department: user.department || '',
      });
    }
  }, [user]);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    setMessage('');
    try {
      const res = await api.put(`/users/${user.id || user._id}`, form);
      updateUser(res.data);
      setMessage('Profile updated successfully.');
      setIsEditing(false);
    } catch (err) {
      setMessage(err.response?.data?.message || 'Update failed');
    } finally {
      setSaving(false);
    }
  };

  if (!user) return null;

  const initials = user?.name?.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2) || '?';

  const profileMenuItems = [
    { icon: '📊', label: 'Dashboard', action: () => navigate('/dashboard') },
    { icon: '📝', label: 'My Assessments', action: () => navigate('/dashboard/assessments') },
    { icon: '📈', label: 'Reports', action: () => navigate('/dashboard/reports') },
  ];

  if (user.role === 'teacher') {
    profileMenuItems.length = 0;
    profileMenuItems.push(
      { icon: '❓', label: 'Questions', action: () => navigate('/teacher/questions') },
      { icon: '👨‍🎓', label: 'Students', action: () => navigate('/teacher/students') }
    );
  }

  if (user.role === 'admin') {
    profileMenuItems.length = 0;
    profileMenuItems.push(
      { icon: '📚', label: 'Subjects', action: () => navigate('/admin/subjects') },
      { icon: '👥', label: 'Users', action: () => navigate('/admin/users') }
    );
  }

  return (
    <div className="profile-page">
      <div className="profile-header">
        <div className="profile-header-content">
          <div className="profile-avatar-section">
            <div className="profile-avatar-large">
              {initials}
            </div>
            <div className="profile-info">
              <h2 className="profile-name">{user.name}</h2>
              <p className="profile-email">{user.email}</p>
            </div>
          </div>
          {!isEditing && (
            <button type="button" className="btn btn-primary edit-profile-btn" onClick={() => setIsEditing(true)}>
              Edit Profile
            </button>
          )}
        </div>
      </div>

      {isEditing ? (
        <div className="profile-edit-card card">
          <div className="edit-header">
            <h3>Edit Profile</h3>
            <button type="button" className="btn-close" onClick={() => setIsEditing(false)}>✕</button>
          </div>
          <form onSubmit={handleSubmit} className="profile-form">
            {message && <div className={`profile-msg ${message.includes('failed') ? 'error' : 'success'}`}>{message}</div>}

            <div className="form-group">
              <label className="label">NAME</label>
              <input type="text" className="input" name="name" value={form.name} onChange={handleChange} required />
            </div>

            <div className="form-group">
              <label className="label">EMAIL</label>
              <input type="text" className="input" value={user.email} disabled />
            </div>

            {user.role === 'teacher' && (
              <div className="form-group">
                <label className="label">ASSIGNED SUBJECTS</label>
                <div className="profile-readonly">
                  {(user.assignedSubjects?.length
                    ? user.assignedSubjects.map(s => s?.name || s).filter(Boolean).join(', ')
                    : 'None (admin assigns subjects to you)')}
                </div>
              </div>
            )}

            {user.role === 'student' && (
              <>
                <div className="form-group">
                  <label className="label">ROLL NUMBER</label>
                  <input type="text" className="input" name="rollNumber" value={form.rollNumber} onChange={handleChange} />
                </div>
                <div className="form-group">
                  <label className="label">COURSE</label>
                  <input type="text" className="input" name="course" value={form.course} onChange={handleChange} />
                </div>
                <div className="form-group">
                  <label className="label">DEPARTMENT</label>
                  <input type="text" className="input" name="department" value={form.department} onChange={handleChange} />
                </div>
              </>
            )}

            <button type="submit" className="btn btn-primary save-btn" disabled={saving}>
              {saving ? 'Saving...' : 'Save changes'}
            </button>
          </form>
        </div>
      ) : (
        <div className="profile-menu-card card">
          <ul className="profile-menu-list">
            {profileMenuItems.map((item, index) => (
              <li key={index} className="profile-menu-item" onClick={item.action}>
                <span className="menu-icon">{item.icon}</span>
                <span className="menu-label">{item.label}</span>
                <span className="menu-arrow">→</span>
              </li>
            ))}
            <li className="profile-menu-divider"></li>
            <li className="profile-menu-item logout-item" onClick={() => {
              const { logout } = require('../context/AuthContext');
              logout();
              navigate('/');
            }}>
              <span className="menu-icon">🚪</span>
              <span className="menu-label">Log Out</span>
              <span className="menu-arrow">→</span>
            </li>
          </ul>
        </div>
      )}
    </div>
  );
}
